<?php require('../../../config.php'); $cmid = required_param('cmid', PARAM_INT); $record = $DB->get_record('local_videotranscriber', ['cmid'=>$cmid]); if (!$record) { echo json_encode(['status'=>'none']); exit; } echo json_encode(['status'=>$record->status]); 2 Interface estilo ChatGPT Abra. nano /var/www/html/moodle/local/videotranscriber/view.php Interface simples estilo chat. view.php.md <?php require('../../config.php'); $cmid = required_param('cmid', PARAM_INT); $cm = get_coursemodule_from_id('url', $cmid); $course = $DB->get_record('course',['id'=>$cm->course]); require_login($course,false,$cm); $PAGE->set_url('/local/videotranscriber/view.php',['cmid'=>$cmid]); $PAGE->set_title('Tutor IA'); $PAGE->set_heading($course->fullname); echo $OUTPUT->header(); echo '<h2>Tutor IA da Aula</h2>'; echo ' <div id="chatbox" style="height:400px;overflow:auto;border:1px solid #ccc;padding:10px;margin-bottom:10px"></div> <input id="question" style="width:80%" placeholder="Pergunte algo sobre a aula"> <button onclick="ask()">Perguntar</button> <script> function addMsg(role,text){ var box=document.getElementById("chatbox"); box.innerHTML += "<p><b>"+role+":</b> "+text+"</p>"; box.scrollTop=box.scrollHeight; } function ask(){ var q=document.getElementById("question").value; addMsg("Aluno",q); fetch("ask.php",{ method:"POST", headers:{ "Content-Type":"application/x-www-form-urlencoded" }, body:"cmid='.$cmid.'&question="+encodeURIComponent(q) }) .then(r=>r.text()) .then(t=>addMsg("Tutor IA",t)); } </script> '; echo $OUTPUT->footer(); 3 Barra de progresso da transcrição Adicione antes do chat. echo ' <div style="margin-bottom:20px"> <div style="background:#eee;height:20px"> <div id="bar" style="background:#4caf50;width:10%;height:20px"></div> </div> <p id="status">Processando transcrição...</p> </div> <script> setInterval(function(){ fetch("/local/videotranscriber/ajax/status.php?cmid='.$cmid.'") .then(r=>r.json()) .then(d=>{ if(d.status=="completed"){ document.getElementById("bar").style.width="100%"; document.getElementById("status").innerText="Transcrição pronta"; } }); },4000); </script> ';
